const Q_GOVERNMENT_1992=[{"id": "objective>Government>1992>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A political authority which exercises sovereign power over a specific geographical area is termed a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">State</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dominion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Leviathan</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A state is a political authority which exercises sovereign power over a specific geographical area. Sovereign power refers to the ultimate overseer, or authority, in the decision-making process of the state and in the maintenance of order. A nation, on the other hand, is a group of people who share common cultural, ethnic, or linguistic ties, but not necessarily a specific geographical area. Dominion is a term used to describe a territory, often with its own governing power, but still under the sovereignty of a larger state. Leviathan is a term from political philosophy, specifically Thomas Hobbes, referring to a powerful central authority.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>1992>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process by which political beliefs and values are transmitted from one generation to another is best known as political</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Socialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Culture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Training</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decentralization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Political socialization is the process by which political beliefs and values are transmitted from one generation to another. This process can occur through various means, such as family, education, media, and peers. Political culture, on the other hand, refers to the shared beliefs and values about the political system of a particular society. Training is a process of learning specific skills or behavior, while decentralization is the process of distributing or dispersing functions, powers, people or things away from a central location or authority.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL PROCESSES: POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>1992>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fusion of the executive and legislative organs of government is associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Monarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presidential system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fascism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parliamentary system</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fusion of the executive and legislative organs of government is associated with the parliamentary system. In a parliamentary system, the executive branch derives its democratic legitimacy from, and is held accountable to, the legislature (parliament); the executive and legislative branches are thus interconnected. In a monarchy, the head of state is usually in a different branch than the head of government. In a presidential system, the executive and legislative branches are separate. Fascism is a form of far-right, authoritarian government that does not necessarily involve a fusion of executive and legislative powers.</div>", "topic": "SYSTEMS OF GOVERNANCE : PARLIAMENTARY SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>1992>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One criticism of delegated legislation is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Subjects citizens to executive decrees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makes laws too flexible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makes laws too technical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is not useful in emergency situation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Delegated legislation (also known as secondary or subordinate legislation) refers to laws made by an authority other than the legislature, typically by a government minister or a regulatory body, under powers granted by an Act of Parliament. <br/>  <br/> The criticism that it \"makes laws too flexible\" stems from the fact that delegated legislation can be changed or amended with relative ease, without the full scrutiny and debate required in the primary legislative process. While flexibility allows for quicker responses to changing circumstances or technical details, it also means that laws can be adapted or altered without the level of democratic oversight and transparency typically associated with primary legislation passed by Parliament. <br/>  <br/> This flexibility is often seen as problematic because: <br/>  <br/> Lack of Parliamentary Scrutiny: Delegated legislation often doesn't go through the same detailed discussion and scrutiny in Parliament, making it more susceptible to changes that might not fully represent the will or interests of the public. <br/>  <br/> Overuse of Power: Government ministers or agencies might change laws or introduce new regulations without sufficient accountability, leading to concerns about the concentration of power in the hands of the executive branch. <br/>  <br/> Uncertainty and Unpredictability: Citizens and businesses might find it hard to keep up with frequent changes in delegated laws that don't go through the same checks and balances as primary legislation, leading to confusion or inconsistency. <br/>  <br/> In comparison, the other options don't capture the core criticism: <br/>  <br/> a. subject citizens to executive degree: While this is another criticism (it gives executive branches more power), it doesn't specifically address the flexibility of the laws. <br/> c. makes laws too technical: Delegated legislation can be technical in nature, but the flexibility criticism focuses on how often and easily it can be changed, rather than its technicality. <br/> d. is not useful in emergency situations: Delegated legislation can actually be very useful in emergencies, as it allows for quick adjustments to the law without needing to wait for the lengthy process of full legislative debate. <br/> Thus, the most fitting answer is b. makes laws too flexible.</div>", "topic": "PROCESSES OF LEGISLATION : DECREES"}, {"id": "objective>Government>1992>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A system of government in which the central government is supreme over other levels is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Totalitarian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Confederal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unitary</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A system of government in which the central government is supreme over other levels is a unitary system. In a unitary system, the central government holds primary authority, and any administrative divisions exercise only powers that the central government chooses to delegate. A totalitarian system is one where the state holds total authority over the society and seeks to control all aspects of public and private life. A confederal system is a union of sovereign states, united for purposes of common action. A federal system is one where power is divided between a central authority and constituent political units.</div>", "topic": "STRUCTURES OF GOVERNANCE : UNITARY FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>1992>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following ideologies advocates governmental control over all sources of power?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Totalitarianism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Feudalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Democracy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Totalitarianism is a political system or a form of government that prohibits opposition parties, restricts individual opposition to the state and its claims, and exercises an extremely high degree of control over public and private life. It is regarded as the most extreme and complete form of authoritarianism.</div>", "topic": "POLITICAL IDEOLOGIES : TOTALITARIANISM"}, {"id": "objective>Government>1992>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT an an acceptable means of achieving democracy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">referendum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">initiative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">riots</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Riots are not an acceptable means of achieving democracy. Democracy is a system of government where the citizens exercise power by voting. In a direct democracy, the citizens as a whole form a governing body and vote directly on each issue. In a representative democracy the citizens elect representatives from among themselves. Riots, on the other hand, are a form of civil disorder commonly characterized by a group lashing out in a violent public disturbance against authority, property or people.</div>", "topic": "PRINCIPLES OF DEMOCRATIC GOVERNMENT : CONSTITUTIONALISM, RULE OF LAW AND REPRESENTATIVE GOVERNMENT"}, {"id": "objective>Government>1992>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the cabinet system of government individual responsibility of ministers means that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">only ministers can be held responsible for errors</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a minister must hold his subordinates responsible for his failures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the prime minister can remove an erring minister</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no individual can be held responsible for government decisions</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the cabinet system of government, individual responsibility of ministers means that the prime minister can remove an erring minister. This is because the ministers are appointed by the prime minister and he has the power to dismiss them.</div>", "topic": "SYSTEMS OF GOVERNANCE : PARLIAMENTARY SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>1992>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of collective responsibility does not operate under the presidential system of government because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cabinet members are responsible people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the legislative and the executive work together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the executive is elected for a fixed term</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the judiciary will overrule the impeachment of the cabinet</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of collective responsibility does not operate under the presidential system of government because the executive is elected for a fixed term. In a presidential system, the president is both the head of state and head of government, and his cabinet members cannot force him to resign by voting 'no confidence'.</div>", "topic": "SYSTEMS OF GOVERNANCE : PRESIDENTIAL SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>1992>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Law making under military regimes is done through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">delegated legislation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">administrative enactments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the promulgation of decrees</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ministry of justice</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Law making under military regimes is done through the promulgation of decrees. A decree is a rule of law usually issued by a head of state (such as the president of a republic or a monarch), according to certain procedures. It has the force of law.</div>", "topic": "PROCESSES OF LEGISLATION : DECREES"}, {"id": "objective>Government>1992>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most critical debates on a bill and amendments to it take place during the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">first reading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">second reading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">third reading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The second reading of a bill is where the most critical debates and amendments take place. This is the stage where the general principles and themes of the bill are considered. If the bill is very complex, it may be committed to a Public Bill Committee or the House may resolve itself into a Committee of the Whole House, but not until two days after the second reading debate.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>1992>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental rights of citizens include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">social security and free speech</div>", "<div style=\"font-family:Cambria;font-size:17px;\">religious freedom and collective aggression</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> immunity from libel and right to employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">right to life and liberty</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental rights of citizens include the right to life and liberty. These are basic human rights that are protected by law in most democratic societies. They are considered fundamental because they are essential for individual freedom, dignity, and personal development.</div>", "topic": "CITIZENSHIP : CITIZENSHIP RIGHTS"}, {"id": "objective>Government>1992>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Electoral colleges have been criticized because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are very expensive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">create more seats in the legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make the legislature too responsive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sometimes negate the wishes of the electorate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electoral colleges have been criticized because they sometimes negate the wishes of the electorate. This is because the system allows for the possibility that a candidate who loses the popular vote can win the electoral college and thus the presidency, which has happened in several U.S. presidential elections.</div>", "topic": "THE ELECTORAL PROCESS : ELECTION – TYPES, INGREDIENTS OF FREE AND FAIR ELECTION."}, {"id": "objective>Government>1992>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Universal adult suffrage is usually restricted in most political systems to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">those with landed property</div>", "<div style=\"font-family:Cambria;font-size:17px;\">literates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> those not more than 70 years old</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Universal adult suffrage is usually restricted in most political systems to citizens. Universal suffrage means that the right to vote should not be restricted by race, sex, belief, wealth, or social status. However, it is generally accepted that this right is reserved for citizens of the country.</div>", "topic": "THE ELECTORAL PROCESS : SUFFRAGE – EVOLUTION, TYPES"}, {"id": "objective>Government>1992>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An election in which citizens are called upon to vote for or against a specified issue is called a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mandate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">referendum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by election</div>", "<div style=\"font-family:Cambria;font-size:17px;\">run off election</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A referendum is an election in which citizens are called upon to vote for or against a specified issue. This is a form of direct democracy where citizens are given the power to decide on specific issues or proposals.</div>", "topic": "THE ELECTORAL PROCESS : ELECTION – TYPES, INGREDIENTS OF FREE AND FAIR ELECTION."}, {"id": "objective>Government>1992>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important objective of political parties is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elect their spokesmen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lobby the government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">from effective national organizations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control the government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of political parties is to control the government. This is because political parties are formed with the aim of capturing political power through the electoral process and use that power to implement their policies and programs.</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES – DEFINITION, ORGANIZATION, FUNCTIONS."}, {"id": "objective>Government>1992>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of a pressure group is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> win and control governmental power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elect their officials</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> influence government policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organize worker to confront government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary function of a pressure group is to influence government policy. Pressure groups are organized groups of people who come together to attempt to influence public policies and decisions. They do not seek to control or become part of the government, but rather to influence its decisions.</div>", "topic": "PRESSURE GROUPS : DEFINITION, TYPES, FUNCTIONS AND MODES OF OPERATION."}, {"id": "objective>Government>1992>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The biased presentation of information in order to influence public opinion is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mobilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propaganda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indoctrination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distortio</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The biased presentation of information in order to influence public opinion is referred to as propaganda. Propaganda is a form of communication that is aimed at influencing the attitude of a community toward some cause or position by presenting only one side of an argument.</div>", "topic": "PUBLIC OPINION : MEANING, FORMATION AND MEASUREMENT"}, {"id": "objective>Government>1992>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was a great military and political power before the colonization of Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the idoma kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the nupe kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the kwararafa empire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the lgala empire</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Kwararafa Empire was a great military and political power before the colonization of Nigeria. The empire was located in what is now the northeastern part of Nigeria and was known for its military strength and political influence.</div>", "topic": "PRE-COLONIAL POLITICS : OTHER PRE-COLONIAL SYSTEMS IN NIGERIA"}, {"id": "objective>Government>1992>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Yoruba traditional governmental system was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Egalitarian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Republican</div>", "<div style=\"font-family:Cambria;font-size:17px;\">democratic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monarchical</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Yoruba traditional governmental system was monarchical. This means that it was ruled by a monarch (a king or queen) who inherited their position, often for life. The monarch had absolute authority in the government.</div>", "topic": "PRE-COLONIAL POLITICS : YORUBA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>1992>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the pre-colonial period in Eastern Nigeria autocratic rule was made difficult by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> activities of secret societies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ruler's fear of detronement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of a system of centralized authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demands of pressure groups</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the pre-colonial period in Eastern Nigeria, autocratic rule was made difficult by the absence of a centralized authority system. This is because the Igbo society, which was predominant in Eastern Nigeria, was largely acephalous (without a central authority) and decisions were made by a council of elders rather than a single ruler.</div>", "topic": "PRE-COLONIAL POLITICS : IGBO PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>1992>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Vassalage as a political system was practised by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lbibio and lgala</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tiv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Haua Fulani</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lgbo and Efik</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vassalage as a political system was practiced by the Hausa Fulani. Vassalage is a system of mutual obligations between a monarch and his or her subjects, where the subjects (vassals) owe allegiance and service to the monarch, and in return, the monarch provides protection and privileges to the vassals. This system was prevalent in the Hausa-Fulani political system where the Emir was the monarch and the district heads were the vassals.</div>", "topic": "PRE-COLONIAL POLITICS : OTHER PRE-COLONIAL SYSTEMS IN NIGERIA"}, {"id": "objective>Government>1992>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was NOT a feature of colonial administration in Nigera?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">forced labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low prices for exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxes on the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">education levy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Education levy was not a feature of colonial administration in Nigeria. The colonial administration was characterized by forced labour, low prices for exports, and taxes on the population. However, education was not a priority for the colonial administration, and there was no levy imposed for education.</div>", "topic": "IMPERIALIST PENETRATION : IMPACT OF BRITISH COLONIAL RULE- ECONOMIC, POLITICAL, SOCIO-CULTURAL"}, {"id": "objective>Government>1992>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dual mandate was proposed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hugh Clapperton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hugh Clifford</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lord Lugard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">George Goldie</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of Dual Mandate was proposed by Lord Lugard. The Dual Mandate, in colonial administration, refers to the policy which held that colonial powers had a duty to administer their colonies in a manner that benefitted both the colonial power and the colony. This policy was a key part of Lord Lugard's administration in Nigeria.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : HUGH CLIFFORD CONSTITUTION 1922"}, {"id": "objective>Government>1992>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Aba women riot was caused by the attempt to introduce</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Indirect Rule to Southern Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the warrant chief system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forced labour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Aba Women's Riot, also known as the Aba Women's Revolt, occurred in 1929 in what is now southeastern Nigeria. It was caused by the British colonial government's attempt to introduce a system of taxation for women. This system was part of the British colonial policies that sought to impose taxes on the indigenous population, and the specific tax affected the women who were market traders, as they would be required to pay taxes on their businesses and property. <br/>  <br/> Additionally, the British tried to introduce a system of \"warrant chiefs,\" a new form of local governance that undermined traditional Igbo leadership. These changes led to a significant backlash from the women, who were deeply involved in the economic and political life of their communities. <br/>  <br/> The Aba Women's Riot was a large-scale uprising by thousands of women in southeastern Nigeria, and it played a key role in raising awareness about the oppressive colonial policies and the resistance to them.</div>", "topic": "PROCESS OF DECOLONIZATION : NATIONALIST MOVEMENTS – EMERGENCE, GOALS, STRATEGIES"}, {"id": "objective>Government>1992>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the unique innovations of the 1951 constitution was the introductions of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Regional premiers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the office of the speaker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the office of the prime minister</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regional executives</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 1951 constitution of Nigeria introduced the concept of regional premiers. This was a unique innovation as it allowed for a degree of regional autonomy and the decentralization of power.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : JOHN MACPHERSON CONSTITUTION 1951"}, {"id": "objective>Government>1992>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To qualify to be president of the federal republic of Nigeria under the 1979 constitution , a candidate must</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be at least 40 years of age</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be a Nigerian by birth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have the highest number of votes cast at the election</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have not less than 1/4 of the votes cast at the election in each of at least 2/3 of all states in the federation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the 1979 constitution of Nigeria, a candidate must be a Nigerian by birth to qualify to be president. This is to ensure that the highest office in the country is held by a citizen who has a deep-rooted connection to the country.</div>", "topic": "POST - INDEPENDENCE CONSTITUTIONS : 1979 CONSTITUTION CHARACTERISTICS AND SHORTCOMINGS"}, {"id": "objective>Government>1992>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">By statute, the main responsibility of the armed forces of Nigeria is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">from a military government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maintain law and order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defend the sovereignty and territorial integrity of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">take part in peace -keeping operations in troubled neighbouring countries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main responsibility of the armed forces of Nigeria, as defined by statute, is to defend the sovereignty and territorial integrity of the country. This means that they are tasked with protecting the country from external threats and maintaining its borders.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>1992>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest court in Nigeria before 1963 was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supreme court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high court</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> judicial committees of the privy council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">court of appeal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Before 1963, the highest court in Nigeria was the Judicial Committee of the Privy Council. This was a British institution that served as the final court of appeal for many British colonies and dominions.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>1992>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary factor which led to the formation of political parties in colonial Nigeria was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">introduction of the elective principle and representative institution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased wealth of the indigenous elite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granting of seif government by the colonial administration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">call by black people all over the world for a final assault on colonialism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary factor which led to the formation of political parties in colonial Nigeria was the introduction of the elective principle and representative institution. This allowed for the participation of Nigerians in the political process and led to the formation of political parties to represent different interests.</div>", "topic": "PROCESS OF DECOLONIZATION : NATIONALIST MOVEMENTS – EMERGENCE, GOALS, STRATEGIES"}, {"id": "objective>Government>1992>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three of the principles used in revenue allocation in Nigeria are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">national interest cultural ethnocentrism and national unity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land mass, primary school enrolment and Geographical location</div>", "<div style=\"font-family:Cambria;font-size:17px;\">derivation, equality and even development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">needs, derivation and relative stability</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principles used in revenue allocation in Nigeria are derivation, equality and even development. Derivation principle implies that states from which natural resources are extracted should get a higher share of the revenue generated from these resources. Equality principle means that all states should be treated equally in terms of revenue allocation. Even development principle implies that revenue allocation should be done in such a way that it promotes balanced development of all parts of the country.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : PROBLEMS OF NIGERIAN FEDERALISM – CENSUS, REVENUE ALLOCATION, CONFLICTS ETC"}, {"id": "objective>Government>1992>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The results of the 1973 census in Nigeria were rejected because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the figures were unacceptable to the U.N.B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the figures were controversial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerians were contented with the existing population figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there were preparations for a fresh census</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The results of the 1973 census in Nigeria were rejected because the figures were controversial. The controversy arose due to allegations of manipulation of the census figures by some regions to gain political and economic advantages.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : PROBLEMS OF NIGERIAN FEDERALISM – CENSUS, REVENUE ALLOCATION, CONFLICTS ETC"}, {"id": "objective>Government>1992>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the advantages of privatization is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">relieves government of its liquidity problem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">makes the poor to be richer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gives private individuals control over public corporations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make public corporations more effective</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the advantages of privatization is that it makes public corporations more effective. Privatization is the process of transferring ownership of a business, enterprise, agency, public service, or public property from the public sector (a government) to the private sector, either to a business that operates for a profit or to a nonprofit organization. It often leads to improved efficiency and effectiveness due to the profit motive and the competitive pressures of the private sector.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS : DEREGULATION, PRIVATIZATION, COMMERCIALIZATION – OBJECTIVES, FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>1992>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important aspect of the 1976 Local Government Reforms was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> introduction of a uniform system of local government</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> introduction of party politics at the local levels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surbordination of local governments to the federal and state governments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recognition of local government as autonomus and sovereign government</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important aspect of the 1976 Local Government Reforms was the introduction of a uniform system of local government. This reform was aimed at making local governments more effective in delivering public services by standardizing their structure, functions and financial management.</div>", "topic": "LOCAL GOVERNMENT :FEATURES OF LOCAL GOVERNMENT REFORMS 1976, 1989 - STRUCTURE, FUNCTIONS, FINANCE AND INTER-GOVERNMENTAL RELATIONS"}, {"id": "objective>Government>1992>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Local governments were created in Nigeria mainly to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">realise the objective of full employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bring government nearer to the people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent the creation of more states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage competition and rivalry amongst ethinc groups</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Local governments were created in Nigeria mainly to bring government nearer to the people. The creation of local governments is aimed at decentralizing power and making governance more participatory and responsive to local needs and aspirations.</div>", "topic": "LOCAL GOVERNMENT : LOCAL GOVERNMENT ADMINISTRATION PRIOR TO 1976"}, {"id": "objective>Government>1992>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Military Government launched the Second National Development Plan in 1970 purposely</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">to develop all the disadvantaged states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to accelerate the development of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for rapid economic and social development of the cuntry after the civil war</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to further the cause of a united, strong and self reliant nation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Second National Development Plan in Nigeria (1970-1974) was launched after the Nigerian Civil War. Its main objective was to rebuild the nation and its economy after the devastating effects of the war. Therefore, the correct answer is 'for rapid economic and social development of the country after the civil war'.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS : STRUCTURE OF MILITARY REGIMES"}, {"id": "objective>Government>1992>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A feature unique to General Murtala Muhammed's Supreme Military Council as compared to that of General Yakubu Gowon was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inclusion of civilians as members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exculsion of military governors from the council</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> inclusion of the chief justice as a member</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exclusion of the Inspector General of Police from the council</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">General Murtala Muhammed's Supreme Military Council was unique in that it excluded military governors from the council. This was a departure from the practice under General Yakubu Gowon's regime, where military governors were part of the council.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS : STRUCTURE OF MILITARY REGIMES"}, {"id": "objective>Government>1992>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major problem of military governments in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absence of proper accountability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abolition of the post of ombudsman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of the rule of law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouragement of foreign investors</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major problem of military governments in Nigeria, as in many other countries, is the absence of proper accountability. Military governments are not elected and therefore do not have to answer to the public in the same way that democratically elected governments do. This can lead to corruption and misuse of power.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS : IMPACT OF MILITARY RULE"}, {"id": "objective>Government>1992>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In 1973, following an OAU resolution, Nigeria broke diplomatic relations with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">France</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Israel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cuba</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In 1973, Nigeria broke diplomatic relations with South Africa. This was in line with an Organization of African Unity (OAU) resolution, which called for member states to sever ties with South Africa due to its apartheid policy.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH MAJOR POWERS"}, {"id": "objective>Government>1992>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's foreign policy of non-alignment was a reaction to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">British imperialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">East-West ideological competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">militarism of ex-colonial powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Third World poverty</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's foreign policy of non-alignment was primarily a reaction to the East-West ideological competition during the Cold War. As a non-aligned nation, Nigeria did not formally align itself with or against any major power bloc.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}, {"id": "objective>Government>1992>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries had a strained relationship countries had a strained relationship with Nigeria over the Angolan crisis of 1975?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> the Soviet Union</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tanzania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the United States of America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the Angolan crisis of 1975, Nigeria and the United States of America had a strained relationship. This was due to the fact that the US supported the FNLA and UNITA factions in the Angolan civil war, while Nigeria supported the MPLA faction which was also supported by the Soviet Union and Cuba.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH MAJOR POWERS"}, {"id": "objective>Government>1992>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major liberation organization which fought for Namibia's independence was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SWAPO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ANC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">FRELIMO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MPLA</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The South West Africa People's Organization (SWAPO) was the major liberation organization that fought for Namibia's independence from South Africa. The ANC fought for South Africa's independence, FRELIMO for Mozambique's and MPLA for Angola's.</div>", "topic": "RELATIONS WITH AFRICAN COUNTRIES : AFRICA AS THE “CENTRE PIECE” OF NIGERIA’S FORIEIGN POLICY"}, {"id": "objective>Government>1992>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In first republic, Nigeria was very reluctant to have meaningful interaction with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Italy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Soviet Union</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the United States of America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Germany</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the first republic, Nigeria was very reluctant to have meaningful interaction with The Soviet Union. This was due to the Cold War politics of the time, where Nigeria, like many other African countries, was trying to maintain a non-aligned position.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH MAJOR POWERS"}, {"id": "objective>Government>1992>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these international organization which the predecessor of the United Nations?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the European Economic Community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Organisation of American States</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the League of Nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the North Atlantic Treaty Organization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The League of Nations was the international organization that was the predecessor of the United Nations. It was established after World War I under the Treaty of Versailles, but it failed to prevent World War II, leading to its dissolution and the subsequent establishment of the United Nations.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>1992>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dramatic rise in the membership of the UN during late 1991 and early 1992 is best accounted for by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">admission of a large number of newly independent African states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appointment of the first African as Secretary-General</div>", "<div style=\"font-family:Cambria;font-size:17px;\">break -up of the Soviet Union into independent Republics</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> expansion of the membership of the Security Council</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dramatic rise in the membership of the UN during late 1991 and early 1992 is best accounted for by the break-up of the Soviet Union into independent Republics. This led to the admission of several new countries into the UN.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>1992>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following ideologies advocates governmental control over all sources of power?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Totalitarianism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Feudalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Democracy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Totalitarianism is a political system or a form of government that prohibits opposition parties, restricts individual opposition to the state and its claims, and exercises an extremely high degree of control over public and private life. It is regarded as the most extreme and complete form of authoritarianism. In totalitarian states, political power has often been held by autocrats who employ all-encompassing campaigns in which propaganda is broadcast by state-controlled mass media.</div>", "topic": "POLITICAL IDEOLOGIES : TOTALITARIANISM"}, {"id": "objective>Government>1992>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Northern People's Congress' stand during the nationalist struggle for Nigeria's independence was for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">immediate independence for Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gradual evolution towards independence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the continuation of British rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independence in 1956</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Northern People's Congress (NPC) was a political party in Nigeria. Formed in June 1949, the party held considerable influence in the Northern Region from the 1950s until the military coup of 1966. During the nationalist struggle for Nigeria's independence, the NPC was more cautious and wanted a gradual evolution towards independence, rather than immediate independence.</div>", "topic": "PROCESS OF DECOLONIZATION : NATIONALIST MOVEMENTS – EMERGENCE, GOALS, STRATEGIES"}, {"id": "objective>Government>1992>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Constituent Assembly of 1978 had the primary responsiblity of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drafting a constitution for the second republic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deliberating on, debating and amending the draft constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reinstating the head of state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">making local government reforms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Constituent Assembly of 1978 in Nigeria was primarily responsible for deliberating on, debating and amending the draft constitution. The assembly was not responsible for drafting the constitution, reinstating the head of state, or making local government reforms.</div>", "topic": "POST - INDEPENDENCE CONSTITUTIONS : 1979 CONSTITUTION CHARACTERISTICS AND SHORTCOMINGS"}, {"id": "objective>Government>1992>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest decision making body under the Buhari regime was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Armed Forces Ruling Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supreme Military Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Council of States</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Federal Executive Council</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the Buhari regime, the highest decision-making body was the Supreme Military Council. The Armed Forces Ruling Council, National Council of States, and Federal Executive Council were not the highest decision-making bodies under this regime.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS : STRUCTURE OF MILITARY REGIMES"}, {"id": "objective>Government>1992>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1979 constitution, the functions of the Civil Service Commission includes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">appointment of Civil Service Commissioners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appointment, promotion and discipline of civil servants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negotiating better conditions for civil servants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Creating ministries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1979 constitution, the functions of the Civil Service Commission include the appointment, promotion, and discipline of civil servants. The commission does not appoint Civil Service Commissioners, negotiate better conditions for civil servants, or create ministries.</div>", "topic": "PUBLIC COMMISSIONS ESTABLISHED BY THE 1979 AND SUBSEQUENT CONSTITUTIONS : THE CIVIL SERVICE COMMISSION"}];
